function displayComments(comments) {
    const commentsContainer = document.getElementById('comments');

    // Clear existing comments safely
    commentsContainer.textContent = '';

    if (!comments || comments.length === 0) {
        const noCommentsMsg = document.createElement('p');
        noCommentsMsg.textContent = 'No comments yet.';
        commentsContainer.appendChild(noCommentsMsg);
        return;
    }

    comments.forEach(function (comment) {
        const commentDiv = document.createElement('div');
        commentDiv.className = 'comment';

        // Display the author name safely using textContent to prevent XSS
        if (comment.author) {
            const authorElement = document.createElement('strong');
            authorElement.textContent = comment.author;
            commentDiv.appendChild(authorElement);
        }

        // Display the timestamp safely if available
        if (comment.timestamp) {
            const timestampElement = document.createElement('span');
            timestampElement.className = 'comment-timestamp';
            timestampElement.textContent = ' — ' + comment.timestamp;
            commentDiv.appendChild(timestampElement);
        }

        // Display the comment text safely using textContent to prevent XSS
        const textElement = document.createElement('p');
        textElement.textContent = comment.text || '';
        commentDiv.appendChild(textElement);

        commentsContainer.appendChild(commentDiv);
    });
}

